# Reverse lookup: 10-digit PSGC code → city/municipality display name
PSGC_CITY_BY_CODE: dict[str, str] = {v: k for k, v in PSGC_CITY.items()}

# Frontend province short-code → 10-digit PSGC code
# Covers all codes used in addressData.json (currently NCR district + 3 Central Luzon provinces).
# Add entries here when new provinces are added to the frontend.
PSGC_PROVINCE_SHORT: dict[str, str] = {
    # NCR — no standard province level; omit PSGC coding for NCR district entries
    'NCR, All District': '',
    # Region III (Central Luzon)
    'PAMP': '0305400000',  # Pampanga
    'BUL':  '0301400000',  # Bulacan
    'ZMB':  '0307100000',  # Zambales
}


def city_psgc(name: str) -> str | None:
    """Return 10-digit PSGC code for a city/municipality display name, or None."""
    return PSGC_CITY.get(name)

def city_display(code: str) -> str | None:
    """Return display name for a 10-digit PSGC city/municipality code, or None."""
    return PSGC_CITY_BY_CODE.get(code)

def province_psgc(name: str) -> str | None:
    """Return 10-digit PSGC code for a province display name or frontend short code, or None."""
    return PSGC_PROVINCE.get(name) or PSGC_PROVINCE_SHORT.get(name) or None

def region_psgc(name: str) -> str | None:
    """Return 10-digit PSGC code for a region name or short code (NCR, III, etc.), or None."""
    return PSGC_REGION.get(name) or PSGC_REGION_SHORT.get(name)